import React from "react";
import TaskForm from "./components/TaskForm";
import TaskList from "./components/TaskList";

function App() {
  return (
    <div style={{ maxWidth: "800px", margin: "40px auto", padding: "20px" }}>
      <h1 style={{ textAlign: "center" }}>📝 Task Tracker</h1>

      <TaskForm />

      <hr />

      <TaskList />
    </div>
  );
}

export default App;
